local pS = require(script.Parent.Parent.Type)
local rp = {}
local rq = {
	__tostring = function(self)
		return ("RoactHostEvent(%s)"):format(self.name)
	end,
}
setmetatable(rp, {
	__index = function(self, rr)
		local ow = { [pS] = pS.HostEvent, name = rr }
		setmetatable(ow, rq)
		rp[rr] = ow
		return ow
	end,
})
return rp
